import scala.xml._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.model.StatusCodes
import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.stream.ActorMaterializer
import scala.concurrent.ExecutionContextExecutor

object XmlConfigService {
  implicit val system: ActorSystem = ActorSystem("xml-config-service")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  def parseXmlConfig(xmlString: String): Either[String, Map[String, String]] = {
    try {
      val xml = XML.loadString(xmlString)
      val settings = (xml \\ "setting").map { setting =>
        (setting \@ "name") -> (setting \@ "value")
      }.toMap
      Right(settings)
    } catch {
      case ex: Exception => Left(s"Error parsing XML: ${ex.getMessage}")
    }
  }

  val route =
    path("parse-config") {
      post {
        entity(as[String]) { xmlString =>
          parseXmlConfig(xmlString) match {
            case Right(settings) => complete(StatusCodes.OK, settings.toString())
            case Left(error) => complete(StatusCodes.BadRequest, error)
          }
        }
      }
    }

  def main(args: Array[String]): Unit = {
    val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
    println("Server online at http://localhost:8080/")
  }
}